(function(){var defaultConfig={startTime:'2022-06-21',watermarkCount:3,gradient:'linear-gradient(45deg, rgba(255,255,255,0.3), rgba(0,0,0,0.3))',fontSize:'24px',fontFamily:'Arial, sans-serif',width:'430px',height:'200px',rotate:'-45deg',margin:'10%',zIndex:9999,opacity:0.2};function mergeConfig(userConfig){var config={};for(var key in defaultConfig){config[key]=userConfig&&userConfig.hasOwnProperty(key)?userConfig[key]:defaultConfig[key]}config.startTime=new Date(config.startTime);return config}function createWatermarks(config){var container=document.createElement('div');container.style.cssText='position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:'+config.zIndex+';';for(var i=0;i<config.watermarkCount;i++){var watermark=document.createElement('div');watermark.className='site-watermark';var marginPercentage=parseInt(config.margin)/100;var topPosition=marginPercentage+(Math.random()*(1-2*marginPercentage));var leftPosition=marginPercentage+(Math.random()*(1-2*marginPercentage));watermark.style.cssText='position:absolute;user-select:none;-webkit-user-select:none;-moz-user-select:none;-ms-user-select:none;white-space:nowrap;overflow:hidden;font-family:'+config.fontFamily+';font-size:'+config.fontSize+';width:'+config.width+';height:'+config.height+';top:'+(topPosition*100)+'%;left:'+(leftPosition*100)+'%;transform:rotate('+config.rotate+');-webkit-transform:rotate('+config.rotate+');-moz-transform:rotate('+config.rotate+');-ms-transform:rotate('+config.rotate+');-o-transform:rotate('+config.rotate+');opacity:'+config.opacity+';background:'+config.gradient+';-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent;color:transparent;';container.appendChild(watermark)}document.body.appendChild(container)}function updateWatermarks(config){var watermarks=document.getElementsByClassName('site-watermark');var now=new Date();var runningTime=now-config.startTime;var days=Math.floor(runningTime/(1000*60*60*24));var hours=Math.floor((runningTime%(1000*60*60*24))/(1000*60*60));var minutes=Math.floor((runningTime%(1000*60*60))/(1000*60));var seconds=Math.floor((runningTime%(1000*60))/1000);var text='站点运行时长: '+days+'天 '+hours+'小时 '+minutes+'分钟 '+seconds+'秒';for(var i=0;i<watermarks.length;i++){watermarks[i].textContent=text}}function initWatermark(userConfig){var config=mergeConfig(userConfig);createWatermarks(config);updateWatermarks(config);setInterval(function(){updateWatermarks(config)},1000)}function checkBrowserSupport(){return('querySelector'in document&&'addEventListener'in window&&'getComputedStyle'in window)}if(checkBrowserSupport()){document.addEventListener('DOMContentLoaded',function(){initWatermark()});window.customizeWatermark=function(userConfig){var existingWatermarks=document.querySelector('div[style*="pointer-events:none"]');if(existingWatermarks){existingWatermarks.parentNode.removeChild(existingWatermarks)}initWatermark(userConfig)}}else{console.warn('浏览器不支持水印功能所需的特性')}})();